-- 007 — Quellen-Register für die portierten Connectoren (FK-Anker + Tier/Provenienz für Priorisierung).
-- Idempotent. Namen aus den Connector-Objekten, Schedule 3×/Tag.

ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, tier=EXCLUDED.tier, provenienz=EXCLUDED.provenienz, abruf_intervall=EXCLUDED.abruf_intervall;
